class Solution:
    def closedIsland(self, grid):
        # Union-Find brute-force: build connected components, check if any cell
        # in a component lies on the border.
        m, n = len(grid), len(grid[0])
        parent = list(range(m * n))

        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x

        def union(a, b):
            parent[find(a)] = find(b)

        for r in range(m):
            for c in range(n):
                if grid[r][c] == 0:
                    for dr, dc in ((1, 0), (0, 1)):
                        nr, nc = r + dr, c + dc
                        if 0 <= nr < m and 0 <= nc < n and grid[nr][nc] == 0:
                            union(r * n + c, nr * n + nc)

        # For each component root, check if any member is on the border
        border_roots = set()
        for r in range(m):
            for c in range(n):
                if grid[r][c] == 0 and (r == 0 or r == m - 1 or c == 0 or c == n - 1):
                    border_roots.add(find(r * n + c))

        # Count distinct interior-only component roots
        seen = set()
        count = 0
        for r in range(m):
            for c in range(n):
                if grid[r][c] == 0:
                    root = find(r * n + c)
                    if root not in border_roots and root not in seen:
                        seen.add(root)
                        count += 1
        return count

