class Solution:
    def closedIsland(self, grid):
        m, n = len(grid), len(grid[0])

        def flood(r, c):
            if r < 0 or r >= m or c < 0 or c >= n or grid[r][c] != 0:
                return
            grid[r][c] = 1  # mark visited / neutralised
            flood(r + 1, c)
            flood(r - 1, c)
            flood(r, c + 1)
            flood(r, c - 1)

        # Pass 1: erase land connected to any border
        for r in range(m):
            flood(r, 0)
            flood(r, n - 1)
        for c in range(n):
            flood(0, c)
            flood(m - 1, c)

        # Pass 2: count remaining closed islands
        count = 0
        for r in range(m):
            for c in range(n):
                if grid[r][c] == 0:
                    count += 1
                    flood(r, c)
        return count

