var closedIsland = function(grid) {
    const m = grid.length, n = grid[0].length;

    function flood(r, c) {
        if (r < 0 || r >= m || c < 0 || c >= n || grid[r][c] !== 0) return;
        grid[r][c] = 1;
        flood(r + 1, c); flood(r - 1, c);
        flood(r, c + 1); flood(r, c - 1);
    }

    // Pass 1: neutralise border-connected land
    for (let r = 0; r < m; r++) { flood(r, 0); flood(r, n - 1); }
    for (let c = 0; c < n; c++) { flood(0, c); flood(m - 1, c); }

    // Pass 2: count closed islands
    let count = 0;
    for (let r = 0; r < m; r++) {
        for (let c = 0; c < n; c++) {
            if (grid[r][c] === 0) {
                count++;
                flood(r, c);
            }
        }
    }
    return count;
};
